//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Embedded run content and phonetic guides (drawing, object, ruby,
//! contentPart, control)".
//!
//! Each `#[test]` encodes a behavioural constraint mined from
//! ECMA-376 / ISO 29500-1 / MS-OI29500, expressed against stemma's observable
//! surfaces (re-serialized `word/document.xml`, the accept/reject plain-text
//! read, and `stemma::api::validate`).
//!
//! A FAILING assertion is NOT a test bug to be weakened away: it encodes a real
//! Word-compliance gap in the stemma engine. The assertion message carries the
//! rule text + section references so a failure is self-explanatory.
//!
//! Methodology note (consumption vs. save): stemma round-trips untouched run
//! content byte-verbatim, so `xmlContains` on a re-serialized *unedited* doc
//! tests stemma's verbatim-preservation contract (structure survives, ordering
//! is canonical, package stays valid). Consumption semantics ("reads as one
//! object", "guide text absent") are asserted on the read side
//! (`read_accepted`/`read_rejected().to_text()`).

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::{Document, validate};
use zip::write::FileOptions;

// ─── Prelude: minimal-.docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` are
/// `(part_name, xml)` pairs (e.g. `("word/styles.xml", "<w:styles…/>")`) added
/// to the archive with matching `[Content_Types].xml` overrides.
///
/// The document namespace set includes `w`, `r`, `m`, `wp`, `v`, `o`, `a`,
/// `pic` so the spec body fragments (which reference these prefixes) are
/// well-formed XML.
/// Every `r:id="…"` the body uses (objectEmbed, contentPart, …) gets a real
/// relationship and a matching `word/embeddings/<id>.bin` target part, so the
/// fixture is a *valid* package (a dangling reference is a repair/data-loss
/// class the serialize gate refuses to emit).
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let embed_rids: Vec<&str> = body_xml
        .split("r:id=\"")
        .skip(1)
        .filter_map(|rest| rest.split('\"').next())
        .collect();
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math" xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any extra parts (only XML parts supported here).
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let ct = if name.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if name.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{name}" ContentType="{ct}"/>"#,
            name = name
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Default Extension="bin" ContentType="application/vnd.openxmlformats-officedocument.oleObject"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let mut embed_rels = String::new();
    for rid in &embed_rids {
        embed_rels.push_str(&format!(
            r#"<Relationship Id="{rid}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/oleObject" Target="embeddings/{rid}.bin"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{embed_rels}</Relationships>"#
    );

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, xml) in extra_parts {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        for rid in &embed_rids {
            zip.start_file(format!("word/embeddings/{rid}.bin"), opts)
                .unwrap();
            zip.write_all(b"\x00OLE").unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(Cursor::new(docx)).expect("open zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse -> serialize (default export) -> return the re-serialized
/// `word/document.xml`. Panics on parse/serialize error so an import failure is
/// loud (it is itself a finding for the opens-clean specs, which assert on
/// `validate` rather than going through this helper).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// Ordered-substring check: every needle appears, in order, in `haystack`.
/// Used to translate `xmlRegex` ordering expectations (`A .* B .* C`) without
/// pulling in the `regex` crate (not a stemma dependency). This is STRICTER in
/// spirit only for the ordering it asserts; the needles are the literal element
/// open-tags the regex anchors on.
fn ordered_contains(haystack: &str, needles: &[&str]) -> bool {
    let mut from = 0usize;
    for n in needles {
        match haystack[from..].find(n) {
            Some(rel) => from += rel + n.len(),
            None => return false,
        }
    }
    true
}

/// True iff `validate` reports no errors (opens-clean).
fn opens_clean(bytes: &[u8]) -> bool {
    let report = validate(bytes);
    report.ok && report.issues.is_empty()
}

/// Render the validation issues for an assertion message.
fn issues_dump(bytes: &[u8]) -> String {
    let report = validate(bytes);
    format!(
        "ok={} issues={:?}",
        report.ok,
        report
            .issues
            .iter()
            .map(|i| format!("{:?}: {}", i.code, i.message))
            .collect::<Vec<_>>()
    )
}

/// Accept-all plain-text read, trimmed. Panics on parse/project error (loud).
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for accept_text")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

/// Reject-all plain-text read, trimmed.
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for reject_text")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

